queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?action_movies a :Action_Movies .
    ?action_movies p:Title ?title .
    ?action_movies p:Duration ?duration_f .
    FILTER((STR(?duration_f) = "120" || STR(?duration_f) = "120.0"))
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?romantic_comedies a :Romantic_Comedies .
    ?romantic_comedies p:Title ?title .
    ?romantic_comedies p:Duration ?duration_f .
    FILTER((STR(?duration_f) = "120" || STR(?duration_f) = "120.0"))
    BIND(?title AS ?o0)
  }
}

